// 示例2：TypeScript - Copilot Chat 对话式生成代码
// 展示如何在 Copilot Chat 中通过对话生成代码

// === 场景：需要实现一个简单的任务管理功能 ===

// 在 Copilot Chat 中输入：
// "帮我创建一个 TaskManager 类，包含以下功能：
//  1. 添加任务 addTask(title: string): string
//  2. 获取所有任务 getTasks(): Task[]
//  3. 删除任务 deleteTask(id: string): boolean
//  4. 请使用类的方式实现，添加适当的 TypeScript 类型定义"

// 生成的代码可能如下：

interface Task {
  id: string;
  title: string;
  createdAt: Date;
  completed: boolean;
}

class TaskManager {
  private tasks: Task[] = [];

  addTask(title: string): string {
    const task: Task = {
      id: crypto.randomUUID(),
      title,
      createdAt: new Date(),
      completed: false,
    };
    this.tasks.push(task);
    return task.id;
  }

  getTasks(): Task[] {
    return [...this.tasks];  // 返回副本避免外部修改
  }

  deleteTask(id: string): boolean {
    const index = this.tasks.findIndex(t => t.id === id);
    if (index === -1) return false;
    this.tasks.splice(index, 1);
    return true;
  }

  completeTask(id: string): boolean {
    const task = this.tasks.find(t => t.id === id);
    if (!task) return false;
    task.completed = true;
    return true;
  }
}

// 使用示例
const manager = new TaskManager();
const taskId = manager.addTask("完成 Copilot 学习");
console.log("添加的任务ID:", taskId);
console.log("所有任务:", manager.getTasks());

