import requests
from typing import Optional, Dict, Any
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

def get_user_data(user_id: int, base_url: str = "https://api.example.com") -> Optional[Dict[str, Any]]:
    """
    异步获取用户数据

    Args:
        user_id: 用户ID
        base_url: API基础URL

    Returns:
        包含 name 和 email 的字典，或失败时返回 None
