### 示例 3：渐进式构建复杂查询

typescript
// ===== 步骤1：构建基础查询 =====
// 提示："写一个 TypeScript 函数构建 SQL SELECT 查询的基础结构"

interface QueryConfig {
  table: string;
  columns: string[];
  where?: Record<string, any>;
  orderBy?: { column: string; direction: 'ASC' | 'DESC' };
  limit?: number;
}

function buildSelectQuery(config: QueryConfig): string {
  const columns = config.columns.length > 0 
    ? config.columns.join(', ') 
    : '*';

  let query = `SELECT ${columns} FROM ${config.table}`;

  // 后续步骤将添加 WHERE、ORDER BY、LIMIT 等子句
  return query;
}

// ===== 步骤2：添加 WHERE 子句支持 =====
// 提示：在原函数基础上添加 WHERE 条件支持，使用参数化查询防止 SQL 注入

function buildSelectQueryV2(config: QueryConfig): { 
  query: string; 
  params: any[] 
} {
  const columns = config.columns.length > 0 
    ? config.columns.join(', ') 
    : '*';

  let query = `SELECT ${columns} FROM ${config.table}`;
  const params: any[] = [];

  // 添加 WHERE 子句
  if (config.where && Object.keys(config.where).length > 0) {
    const conditions = Object.entries(config.where).map(([key, value]) => {
      params.push(value);
      return `${key} = ?`;
    });
    query += ` WHERE ${conditions.join(' AND ')}`;
  }

  // 添加 ORDER BY
  if (config.orderBy) {
    query += ` ORDER BY ${config.orderBy.column} ${config.orderBy.direction}`;
  }

  // 添加 LIMIT
  if (config.limit) {
    query += ` LIMIT ?`;
    params.push(config.limit);
  }

  return { query, params };
}

// 使用示例
const result = buildSelectQueryV2({
  table: 'users',
  columns: ['id', 'name', 'email'],
  where: { status: 'active', age: { gte: 18 } },
  orderBy: { column: 'created_at', direction: 'DESC' },
  limit: 10
});

console.log(result.query);
// SELECT id, name, email FROM users WHERE status = ? AND age >= ? ORDER BY created_at DESC LIMIT ?
console.log(result.params); // ['active', 18, 10]


## 四、常见问题与注意事项

### 4.1 常见错误

| 错误类型 | 描述 | 解决方法 |
|---------|------|---------|
| 提示过于笼统 | 只说"写个函数"而不说明具体功能 | 提供清晰的功能描述和具体参数 |
| 一次要求太多 | 试图在一个提示中完成所有功能 | 拆分为多个简单任务 |
| 忽略上下文 | 没有提供足够的背景信息 | 添加相关代码片段和注释 |
| 约束条件冲突 | 设置相互矛盾的约束 | 仔细检查需求的逻辑一致性 |
| 不验证中间结果 | 直接使用不完整的代码 | 在每步迭代后验证正确性 |

### 4.2 注意事项

1. **保持提示简洁**：避免在单个提示中塞入过多信息，这会导致 Copilot 生成模糊或不相关的代码。

2. **利用注释引导**：在代码中添加注释说明意图，Copilot 会参考这些注释生成更符合预期的代码。

3. **善用自然语言**：不必使用精确的编程术语，用日常语言描述需求往往效果更好。

4. **注意上下文污染**：之前的代码可能会影响后续生成，确保清理或注释掉不需要的上下文。

5. **区分提示位置**：在函数内部还是外部、在注释中还是文档字符串中输入提示，效果可能不同。

## 五、实践建议

### 5.1 建立迭代优化的习惯

1. **从简单开始**：先用最基础的提示尝试，记录结果
2. **问题驱动**：每次迭代只解决一个问题
3. **记录差异**：记录每次调整带来的变化，积累经验
4. **复用模板**：将成功的提示模式保存为模板

### 5.2 提示优化清单

在提交提示前，检查以下要点：

- [ ] 是否清楚地说明了输入和输出？
- [ ] 是否提供了具体的示例？
- [ ] 是否指定了技术栈和版本要求？
- [ ] 是否包含了边界条件和异常处理要求？
- [ ] 是否说明了代码风格要求？

### 5.3 高效调试技巧

