### 示例 3：TypeScript API 集成测试

typescript
// 待测试的源代码 - userController.ts
import { Request, Response } from 'express';

interface User {
  id: string;
  name: string;
  email: string;
  age?: number;
}

// 模拟的用户数据存储
const users: User[] = [
  { id: '1', name: '张三', email: 'zhangsan@example.com', age: 25 },
  { id: '2', name: '李四', email: 'lisi@example.com', age: 30 }
];

export const getUsers = (req: Request, res: Response): void => {
  const { age, search } = req.query;

  let result = [...users];

  if (age) {
    result = result.filter(u => u.age === Number(age));
  }

  if (search) {
    const searchLower = String(search).toLowerCase();
    result = result.filter(u => 
      u.name.toLowerCase().includes(searchLower) ||
      u.email.toLowerCase().includes(searchLower)
    );
  }

  res.json({ success: true, data: result, count: result.length });
};

export const createUser = (req: Request, res: Response): void => {
  const { name, email, age } = req.body;

  if (!name || !email) {
    res.status(400).json({ 
      success: false, 
      error: '姓名和邮箱为必填项' 
    });
    return;
  }

  if (!email.includes('@')) {
    res.status(400).json({ 
      success: false, 
      error: '邮箱格式无效' 
    });
    return;
  }

  const newUser: User = {
    id: String(Date.now()),
    name,
    email,
    age
  };

  users.push(newUser);

  res.status(201).json({ success: true, data: newUser });
};

export const getUserById = (req: Request, res: Response): void => {
  const { id } = req.params;
  const user = users.find(u => u.id === id);

  if (!user) {
    res.status(404).json({ success: false, error: '用户不存在' });
    return;
  }

  res.json({ success: true, data: user });
};

// Copilot 生成的测试文件 - userController.test.ts
import { Request, Response } from 'express';
import { getUsers, createUser, getUserById } from './userController';

// 辅助函数：创建模拟的 Request 和 Response
const mockRequest = (overrides = {}) => {
  const req = {
    params: {},
    query: {},
    body: {},
    ...overrides
  } as unknown as Request;
  return req;
};

const mockResponse = () => {
  const res = {
    status: jest.fn().mockReturnThis(),
    json: jest.fn().mockReturnThis(),
  } as unknown as Response;
  return res;
};

describe('用户控制器测试套件', () => {
  describe('getUsers - 获取用户列表', () => {
    test('无参数时应返回所有用户', () => {
      const req = mockRequest();
      const res = mockResponse();

      getUsers(req, res);

      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          success: true,
          count: expect.any(Number)
        })
      );
    });

    test('按年龄筛选应返回匹配的用户', () => {
      const req = mockRequest({ query: { age: '25' } });
      const res = mockResponse();

      getUsers(req, res);

      const jsonCall = res.json.mock.calls[0][0];
      expect(jsonCall.success).toBe(true);
      // 验证返回的用户年龄都是25
      jsonCall.data.forEach((user: any) => {
        expect(user.age).toBe(25);
      });
    });

    test('按搜索关键词筛选应返回匹配的用户', () => {
      const req = mockRequest({ query: { search: 'zhang' } });
      const res = mockResponse();

      getUsers(req, res);

      const jsonCall = res.json.mock.calls[0][0];
      expect(jsonCall.data.some((u: any) => u.name === '张三')).toBe(true);
    });

    test('搜索应区分大小写', () => {
      const req = mockRequest({ query: { search: 'ZHANG' } });
      const res = mockResponse();

      getUsers(req, res);

      const jsonCall = res.json.mock.calls[0][0];
      // 应该也匹配到大写的搜索（因为代码中有 toLowerCase）
      expect(jsonCall.data.length).toBeGreaterThan(0);
    });

    test('组合筛选条件应同时生效', () => {
      const req = mockRequest({ query: { age: '25', search: 'zhang' } });
      const res = mockResponse();

      getUsers(req, res);

      const jsonCall = res.json.mock.calls[0][0];
      expect(jsonCall.data.length).toBe(1);
      expect(jsonCall.data[0].name).toBe('张三');
    });
  });

  describe('createUser - 创建用户', () => {
    test('正常创建用户应返回201状态码', () => {
      const req = mockRequest({
        body: {
          name: '王五',
          email: 'wangwu@example.com',
          age: 28
        }
      });
      const res = mockResponse();

      createUser(req, res);

      expect(res.status).toHaveBeenCalledWith(201);
      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          success: true,
          data: expect.objectContaining({
            name: '王五',
            email: 'wangwu@example.com'
          })
        })
      );
    });

    test('缺少姓名字段应返回400错误', () => {
      const req = mockRequest({
        body: { email: 'test@example.com' }
      });
      const res = mockResponse();

      createUser(req, res);

      expect(res.status).toHaveBeenCalledWith(400);
      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          success: false,
          error: '姓名和邮箱为必填项'
        })
      );
    });

    test('缺少邮箱字段应返回400错误', () => {
      const req = mockRequest({
        body: { name: '测试用户' }
      });
      const res = mockResponse();

      createUser(req, res);

      expect(res.status).toHaveBeenCalledWith(400);
    });

    test('无效邮箱格式应返回400错误', () => {
      const req = mockRequest({
        body: { name: '测试用户', email: 'invalid-email' }
      });
      const res = mockResponse();

      createUser(req, res);

      expect(res.status).toHaveBeenCalledWith(400);
      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          success: false,
          error: '邮箱格式无效'
        })
      );
    });

    test('缺少可选的age字段应该正常创建', () => {
      const req = mockRequest({
        body: {
          name: '无年龄用户',
          email: 'noage@example.com'
        }
      });
      const res = mockResponse();

      createUser(req, res);

      expect(res.status).toHaveBeenCalledWith(201);
      const jsonCall = res.json.mock.calls[0][0];
      expect(jsonCall.data.age).toBeUndefined();
    });
  });

  describe('getUserById - 根据ID获取用户', () => {
    test('存在的用户ID应返回用户信息', () => {
      const req = mockRequest({ params: { id: '1' } });
      const res = mockResponse();

      getUserById(req, res);

      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          success: true,
          data: expect.objectContaining({
            id: '1',
            name: '张三'
          })
        })
      );
    });

    test('不存在的用户ID应返回404错误', () => {
      const req = mockRequest({ params: { id: '999' } });
      const res = mockResponse();

      getUserById(req, res);

      expect(res.status).toHaveBeenCalledWith(404);
      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          success: false,
          error: '用户不存在'
        })
      );
    });

    test('边界值：空字符串ID应返回404', () => {
      const req = mockRequest({ params: { id: '' } });
      const res = mockResponse();

      getUserById(req, res);

      expect(res.status).toHaveBeenCalledWith(404);
    });
  });
});


## 常见问题与注意事项

### 1. 生成的测试可能不完整

**问题**：Copilot 生成的测试可能遗漏某些边界情况或异常场景。

**解决策略**：
- 仔细审查生成的测试代码，补充遗漏的场景
- 使用测试覆盖率工具（如 Istanbul、Coverage.py）检查未覆盖的代码路径
- 对关键业务逻辑手动添加更多边界测试

### 2. Mock 对象的过度使用

**问题**：初学者可能为所有依赖都创建 Mock，导致测试脆弱且难以维护。

**注意事项**：
- 只对外部依赖（数据库、API、文件系统）使用 Mock
- 同一模块内的协作类可以创建真实实例进行集成测试
- 避免 Mock 具体实现细节，应该 Mock 接口/协议

### 3. 测试数据硬编码问题

**问题**：生成的测试数据可能过于简单，无法代表真实场景。

**改进方法**：
- 使用测试工厂模式生成多样化的测试数据
- 引入 Faker 库生成真实感强的测试数据
- 为不同场景准备不同的测试数据集

### 4. 测试代码与源代码同步

**问题**：源代码变更后，测试可能失效或变得不准确。

**实践建议**：
- 将测试代码和源代码放在相近的位置
- 使用版本控制管理测试代码
- 定期运行完整测试套件确保同步

### 5. 过度依赖 Copilot

**警示**：不要完全依赖 AI 生成测试，忽视了对测试原则和最佳实践的学习。

**平衡策略**：
- 将 Copilot 作为辅助工具，而非替代品
- 学习测试驱动开发（TDD）方法论
- 理解测试金字塔原理，合理分配不同层次的测试

## 最佳实践

### 1. 提供充分的上下文信息

python
# ❌ 效果较差的提示
"生成测试代码"

# ✅ 效果良好的提示
"""
为 validate_email 函数生成 pytest 测试用例，需要覆盖：
1. 有效的邮箱格式（普通域名、国家域名）
2. 无效格式（缺少@、缺少域名、包含空格）
3. 边界情况（最长邮箱、特特殊字符）
使用 Mock 模拟 DNS 查询验证
"""


### 2. 采用测试数据工厂模式

python
# 创建可复用的测试数据工厂
import factory
from faker import Faker

fake = Faker('zh_CN')

class UserFactory(factory.Factory):
    class Meta:
        model = User

    id = factory.Sequence(lambda n: f'user_{n}')
    name = factory.LazyFunction(lambda: fake.name())
    email = factory.LazyFunction(lambda: fake.email())
    age = factory.LazyFunction(lambda: fake.random_int(min=18, max=80))

# 使用工厂生成测试数据
user1 = UserFactory()  # 随机用户
user2 = UserFactory(name='特定名称')  # 部分固定
users = UserFactory.create_batch(10)  # 批量生成


### 3. 遵循 AAA 模式（Arrange-Act-Assert）

typescript
// 结构化的测试组织方式
test('用户下单流程', () => {
  // Arrange - 准备测试环境和数据
  const cart = createCartWithItems(3);
  const user = createTestUser();
  const paymentService = createMockPaymentService();

  // Act - 执行被测试的操作
  const result = orderService.checkout(cart, user, paymentService);

  // Assert - 验证预期结果
  expect(result.success).toBe(true);
  expect(result.orderId).toBeDefined();
  expect(paymentService.charge).toHaveBeenCalledWith(ANY, cart.total);
});


