#!/usr/bin/env python3
"""
依赖安全检查工具
检查项目依赖中的已知漏洞
"""

import subprocess
import json
from pathlib import Path

def check_npm_dependencies():
    """检查 npm 依赖安全性"""
    print("正在检查 npm 依赖...")
    try:
        result = subprocess.run(
            ['npm', 'audit', '--json'],
            capture_output=True,
            text=True,
            timeout=60
        )
        audit_data = json.loads(result.stdout)

        vulnerabilities = audit_data.get('vulnerabilities', {})
