// 示例：个人模板库的JavaScript实现
// 支持分类管理、快速搜索和变量替换

class PromptTemplateLibrary {
    constructor() {
        this.templates = new Map();
        this.categories = new Map();
    }

    // 添加模板
    addTemplate(name, category, template) {
        // 存储模板
        this.templates.set(name, {
            content: template,
            category: category,
            createdAt: new Date(),
            usageCount: 0
        });

        // 更新分类
        if (!this.categories.has(category)) {
            this.categories.set(category, []);
        }
        this.categories.get(category).push(name);
    }

    // 使用模板（支持变量替换）
    useTemplate(name, variables = {}) {
        const template = this.templates.get(name);
        if (!template) {
            throw new Error(`模板 '${name}' 不存在`);
        }

        // 替换变量：格式 ${variableName}
        let content = template.content;
        for (const [key, value] of Object.entries(variables)) {
            content = content.replace(new RegExp(`\\$\\{${key}\\}`, 'g'), value);
        }

        // 更新使用计数
        template.usageCount++;

        return content;
    }

    // 搜索模板
    search(keyword) {
        const results = [];
        for (const [name, template] of this.templates) {
            if (name.includes(keyword) || template.content.includes(keyword)) {
                results.push({ name, ...template });
            }
        }
        return results;
    }

    // 获取分类统计
    getStats() {
        const stats = {};
        for (const [category, names] of this.categories) {
            stats[category] = names.length;
        }
        return stats;
    }
}

// 使用示例
const library = new PromptTemplateLibrary();

// 添加React组件模板
library.addTemplate('react-component', 'React', `
创建一个React组件：${componentName}
要求：
1. 使用TypeScript
2. 使用函数组件
3. 包含Props类型定义
`);

// 使用模板
const prompt = library.useTemplate('react-component', {
    componentName: 'UserCard'
});
console.log(prompt);

// 输出：\n创建一个React组件：UserCard\n要求：\n1. 使用TypeScript\n2. 使用函数组件\n3. 包含Props类型定义\n

