### 示例 4：文件范围选择与上下文指定

python
# ============================================
# Python 示例：利用文件结构传递上下文
# ============================================

# ============================================
# 项目结构：
# ├── models/
# │   ├── __init__.py
# │   ├── user.py      # 定义 User 模型
# │   └── order.py     # 定义 Order 模型  
# ├── services/
# │   ├── __init__.py
# │   └── user_service.py
# └── utils/
#     └── validators.py
# ============================================

# models/user.py
"""用户数据模型"""
from dataclasses import dataclass
from typing import Optional
from datetime import datetime

@dataclass
class User:
    """用户模型

    Attributes:
        id: 用户唯一标识
        username: 用户名（唯一）
        email: 邮箱地址
        role: 角色（admin/member/guest）
        created_at: 创建时间
    """
    id: str
    username: str
    email: str
    role: str
    created_at: datetime

    @property
    def is_admin(self) -> bool:
        return self.role == 'admin'

# services/user_service.py
"""用户服务层 - 依赖 User 模型"""
from typing import List, Optional
from models.user import User  # 导入声明
from utils.validators import validate_email, validate_username

class UserService:
    """用户服务类

    使用 User 模型进行用户管理操作
    """

    def __init__(self):
        self._users: List[User] = []

    def create_user(self, username: str, email: str, role: str = 'member') -> User:
        """创建新用户

        Args:
            username: 用户名
            email: 邮箱
            role: 角色权限

        Returns:
            创建的 User 实例

        Raises:
            ValueError: 用户名或邮箱格式不正确

        Example:
            >>> service = UserService()
            >>> user = service.create_user('john', 'john@example.com')
            >>> print(user.username)
            'john'
        """
        # 验证输入 - 使用 utils 中的验证器
        if not validate_username(username):
            raise ValueError(f"无效的用户名: {username}")
        if not validate_email(email):
            raise ValueError(f"无效的邮箱: {email}")

        # Copilot 理解需要创建 User 实例
        user = User(
            id=generate_uuid(),
            username=username,
            email=email,
            role=role,
            created_at=datetime.now()
        )
        return user

    def find_by_username(self, username: str) -> Optional[User]:
        """根据用户名查找用户

        Args:
            username: 要查找的用户名

        Returns:
            找到的用户对象，未找到返回 None
        """
        # Copilot 会使用 User 的属性进行比较
        for user in self._users:
            if user.username == username:
                return user
        return None


