from typing import List, Dict, Optional
from dataclasses import dataclass
from datetime import datetime

@dataclass
class Order:
    """订单数据模型"""
    order_id: str
    customer_name: str
    items: List[Dict[str, any]]
    total_amount: float
    status: str
