# 提示："""
# 写一个异步函数 get_user_data：
# - 接收 user_id 参数
# - 使用 requests 库发送 GET 请求到 /api/users/{user_id}
# - 设置超时时间为 10 秒
# - 返回用户对象的 name 和 email 字段
# - 如果请求失败，返回 None 并打印错误日志
# - 包含类型注解
# """

import requests
from typing import Optional, Dict, Any
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

def get_user_data(user_id: int, base_url: str = "https://api.example.com") -> Optional[Dict[str, Any]]:
    """
    异步获取用户数据

    Args:
        user_id: 用户ID
        base_url: API基础URL

    Returns:
        包含 name 和 email 的字典，或失败时返回 None
    """
    try:
        response = requests.get(
            f"{base_url}/api/users/{user_id}",
            timeout=10
        )
        response.raise_for_status()

        data = response.json()
        return {
            "name": data.get("name"),
            "email": data.get("email")
        }
    except requests.exceptions.Timeout:
        logger.error(f"请求用户 {user_id} 超时")
        return None
    except requests.exceptions.RequestException as e:
        logger.error(f"请求用户 {user_id} 失败: {e}")
        return None

# 使用示例
if __name__ == "__main__":
    user = get_user_data(123)
    if user:
        print(f"用户名: {user['name']}, 邮箱: {user['email']}")


