typescript
// ===== 步骤1：构建基础查询 =====
// 提示："写一个 TypeScript 函数构建 SQL SELECT 查询的基础结构"

interface QueryConfig {
  table: string;
  columns: string[];
  where?: Record<string, any>;
  orderBy?: { column: string; direction: 'ASC' | 'DESC' };
  limit?: number;
}

function buildSelectQuery(config: QueryConfig): string {
  const columns = config.columns.length > 0 
    ? config.columns.join(', ') 
    : '*';

  let query = `SELECT ${columns} FROM ${config.table}`;

  // 后续步骤将添加 WHERE、ORDER BY、LIMIT 等子句
  return query;
}

// ===== 步骤2：添加 WHERE 子句支持 =====
// 提示：在原函数基础上添加 WHERE 条件支持，使用参数化查询防止 SQL 注入

function buildSelectQueryV2(config: QueryConfig): { 
  query: string; 
  params: any[] 
} {
  const columns = config.columns.length > 0 
    ? config.columns.join(', ') 
    : '*';

  let query = `SELECT ${columns} FROM ${config.table}`;
  const params: any[] = [];

  // 添加 WHERE 子句
  if (config.where && Object.keys(config.where).length > 0) {
    const conditions = Object.entries(config.where).map(([key, value]) => {
      params.push(value);
      return `${key} = ?`;
    });
    query += ` WHERE ${conditions.join(' AND ')}`;
  }

  // 添加 ORDER BY
  if (config.orderBy) {
    query += ` ORDER BY ${config.orderBy.column} ${config.orderBy.direction}`;
  }

  // 添加 LIMIT
  if (config.limit) {
    query += ` LIMIT ?`;
    params.push(config.limit);
  }

  return { query, params };
}

// 使用示例
const result = buildSelectQueryV2({
  table: 'users',
  columns: ['id', 'name', 'email'],
  where: { status: 'active', age: { gte: 18 } },
  orderBy: { column: 'created_at', direction: 'DESC' },
  limit: 10
});

console.log(result.query);
// SELECT id, name, email FROM users WHERE status = ? AND age >= ? ORDER BY created_at DESC LIMIT ?
console.log(result.params); // ['active', 18, 10]


