// 示例1: Express.js RESTful API 端点生成
// 场景: 为商品管理生成完整的 CRUD 接口

import { Router, Request, Response } from 'express';
import { ProductService } from '../services/productService';

const router = Router();
const productService = new ProductService();

// 获取商品列表 - GET /api/products
router.get('/', async (req: Request, res: Response) => {
    const { page = 1, limit = 20, category, minPrice, maxPrice, keyword } = req.query;

    try {
        const result = await productService.findProducts({
            page: Number(page),
            limit: Number(limit),
            category: category as string,
            minPrice: minPrice ? Number(minPrice) : undefined,
            maxPrice: maxPrice ? Number(maxPrice) : undefined,
            keyword: keyword as string
        });

        res.json({
            success: true,
            data: result.products,
            pagination: {
                total: result.total,
                page: result.page,
                limit: result.limit,
                totalPages: Math.ceil(result.total / result.limit)
            }
        });
    } catch (error) {
        res.status(500).json({
            success: false,
            message: '获取商品列表失败',
            error: error instanceof Error ? error.message : '未知错误'
        });
    }
});

// 获取单个商品 - GET /api/products/:id
router.get('/:id', async (req: Request, res: Response) => {
    const { id } = req.params;

    try {
        const product = await productService.findById(id);

        if (!product) {
            return res.status(404).json({
                success: false,
                message: '商品不存在'
            });
        }

        res.json({
            success: true,
            data: product
        });
    } catch (error) {
        res.status(500).json({
            success: false,
            message: '获取商品详情失败',
            error: error instanceof Error ? error.message : '未知错误'
        });
    }
});

// 创建商品 - POST /api/products
router.post('/', async (req: Request, res: Response) => {
    const productData = req.body;

    try {
        const product = await productService.create(productData);
        res.status(201).json({
            success: true,
            message: '商品创建成功',
            data: product
        });
    } catch (error) {
        if (error instanceof Error && error.message.includes('重复')) {
            return res.status(409).json({
                success: false,
                message: '商品编号已存在'
            });
        }
        res.status(400).json({
            success: false,
            message: '创建商品失败',
            error: error instanceof Error ? error.message : '未知错误'
        });
    }
});

// 更新商品 - PUT /api/products/:id
router.put('/:id', async (req: Request, res: Response) => {
    const { id } = req.params;
    const updateData = req.body;

    try {
        const product = await productService.update(id, updateData);
        res.json({
            success: true,
            message: '商品更新成功',
            data: product
        });
    } catch (error) {
        res.status(400).json({
            success: false,
            message: '更新商品失败',
            error: error instanceof Error ? error.message : '未知错误'
        });
    }
});

