### 示例 2

```python
// 示例2: 数据验证与转换 - 使用 Yup 进行表单验证
// 场景: 用户注册表单的数据验证和转换

import * as Yup from 'yup';

// 定义验证模式
const registerSchema = Yup.object().shape({
    // 用户名: 必填，3-20字符，字母数字下划线
    username: Yup.string()
        .required('用户名不能为空')
        .min(3, '用户名至少3个字符')
        .max(20, '用户名最多20个字符')
        .matches(/^[a-zA-Z0-9_]+$/, '用户名只能包含字母、数字和下划线'),

    // 邮箱: 必填，有效邮箱格式
    email: Yup.string()
        .required('邮箱不能为空')
        .email('请输入有效的邮箱地址'),

    // 密码: 必填，复杂密码要求
    password: Yup.string()
        .required('密码不能为空')
        .min(8, '密码至少8个字符')
        .matches(
            /^(?=.*[a-z])(?=.*[A-Z])(?=.*\\d)(?=.*[@$!%*?&])[A-Za-z\\d@$!%*?&]/,
            '密码必须包含大小写字母、数字和特殊字符'
        ),

    // 确认密码: 必填，与密码一致
    confirmPassword: Yup.string()
        .required('请确认密码')
        .oneOf([Yup.ref('password')], '两次输入的密码不一致'),

    // 手机号: 可选，有效的中国手机号
    phone: Yup.string()
        .optional()
        .matches(/^1[3-9]\\d{9}$/, '请输入有效的手机号码'),

    // 年龄: 可选，16-120之间
    age: Yup.number()
        .optional()
        .min(16, '年龄不能小于16岁')
        .max(120, '请输入有效的年龄'),

    // 同意条款: 必填且必须为 true
    agreeTerms: Yup.boolean()
        .required('请阅读并同意服务条款')
        .oneOf([true], '请阅读并同意服务条款')
});

// 登录验证模式
const loginSchema = Yup.object().shape({
    // 支持用户名或邮箱登录
    account: Yup.string()
        .required('请输入用户名或邮箱')
        .test(
            'is-valid-account',
            '请输入有效的用户名或邮箱',
            (value) => {
                if (!value) return false;
                const isEmail = /^[\\S]+@[\\S]+\\.[\\S]+$/.test(value);
                const isUsername = /^[a-zA-Z0-9_]{3,20}$/.test(value);
                return isEmail || isUsername;
            }
        ),

    password: Yup.string()
        .required('请输入密码')
        .min(1, '密码不能为空')
});

// 数据转换函数
const transformRegisterData = async (rawData: unknown) => {
    // 1. 验证数据
    const validatedData = await registerSchema.validate(rawData, {
        abortEarly: false,
        stripUnknown: true
    });

    // 2. 标准化数据格式
    const normalizedData = {
        username: validatedData.username.toLowerCase().trim(),
        email: validatedData.email.toLowerCase().trim(),
        password: validatedData.password,
        phone: validatedData.phone || null,
        age: validatedData.age || null,
        agreeTerms: validatedData.agreeTerms,
        agreeTermsAt: validatedData.agreeTerms ? new Date() : null,
        createdAt: new Date(),
        updatedAt: new Date(),
        status: 'active'
    };

    // 3. 生成唯一标识符
    const salt = await bcrypt.genSalt(10);
    normalizedData.password = await bcrypt.hash(normalizedData.password, salt);
    normalizedData.userId = generateUUID();

    // 4. 设置默认值
    normalizedData.emailVerified = false;
    normalizedData.lastLoginAt = null;
    normalizedData.loginCount = 0;
    normalizedData.role = 'user';

    return normalizedData;
};

// 验证辅助函数
const validateField = async (
    fieldName: string,
    value: unknown
): Promise<{ isValid: boolean; error?: string }> => {
    const fieldSchema = Yup.reach(registerSchema, fieldName);

    try {
        await fieldSchema.validate(value);
        return { isValid: true };
    } catch (error) {
        if (error instanceof Yup.ValidationError) {
            return { isValid: false, error: error.message };
        }
        return { isValid: false, error: '验证失败' };
    }
};

// 批量验证函数
const validateMultipleFields = async (
    data: Record<string, unknown>
): Promise<{
    success: boolean;
    errors: Record<string, string>;
    validData?: Record<string, unknown>
}> => {
    try {
        const validData = await registerSchema.validate(data, {
            abortEarly: false,
            stripUnknown: true
        });
        return { success: true, errors: {}, validData };
    } catch (error) {
        if (error instanceof Yup.ValidationError) {
            const errors: Record<string, string> = {};
            error.inner.forEach((err) => {
                if (err.path) {
                    errors[err.path] = err.message;
                }
            });
            return { success: false, errors };
        }
        return { success: false, errors: { general: '验证失败' } };
    }
};

export {
    registerSchema,
    loginSchema,
    transformRegisterData,
    validateField,
    validateMultipleFields
};
```



## 常见错误

- 直接使用 Copilot 生成的代码而不进行代码审查，导致安全漏洞（如 SQL 注入、XSS 等）
- 提供过少的上下文（仅一个函数名）导致生成不相关或错误的代码
- 生成的代码缺少适当的错误处理和边界情况检查
- 不定义类型注解导致代码中出现大量 any 类型，降低代码质量
- 期望 Copilot 理解复杂的业务规则，生成错误的业务逻辑实现
- 生成的代码未考虑项目现有的代码规范和风格，导致团队代码不一致
- 对敏感操作（支付、权限等）直接使用 Copilot 生成代码而未进行安全审计
- 一次性生成大量代码而未逐段验证，导致错误难以定位


## 最佳实践

- 始终提供清晰的代码上下文，包括函数签名、类型定义和相关注释
- 将 Copilot 作为起点而非终点，必须人工审核生成的代码
- 先定义好接口和类型，再让 Copilot 补全实现细节
- 对生成的业务逻辑代码编写单元测试，确保正确性
- 敏感操作（认证、支付、数据删除）必须经过安全专家审核
- 保持提示词简洁明确，使用中文详细描述业务需求
- 使用 JSDoc 注释增强 Copilot 对代码的理解和生成准确性
- 定期复盘 Copilot 生成代码的质量，持续优化使用方式

