### 示例二：数据模型与 ORM 代码生成

**场景**：使用 TypeORM 定义用户数据模型

typescript
// user.entity.ts
// 用户实体 - 定义用户数据模型结构

import {
    Entity,
    PrimaryGeneratedColumn,
    Column,
    CreateDateColumn,
    UpdateDateColumn,
    OneToMany,
    BeforeInsert,
    BeforeUpdate
} from 'typeorm';
import { Order } from './order.entity';

// 用户角色枚举
export enum UserRole {
    ADMIN = 'admin',
    USER = 'user',
    GUEST = 'guest'
}

// 用户状态枚举
export enum UserStatus {
    ACTIVE = 'active',
    INACTIVE = 'inactive',
    BANNED = 'banned'
}

@Entity('users')
export class User {
    // 主键 - 自动递增
    @PrimaryGeneratedColumn('uuid')
    id!: string;

    // 用户名 - 唯一且非空
    @Column({ unique: true, length: 50 })
    username!: string;

    // 邮箱 - 唯一且非空
    @Column({ unique: true, length: 100 })
    email!: string;

    // 密码哈希 - 不返回给前端
    @Column({ select: false })
    passwordHash!: string;

    // 用户昵称
    @Column({ length: 100, nullable: true })
    nickname?: string;

    // 手机号码
    @Column({ length: 20, nullable: true })
    phone?: string;

    // 头像 URL
    @Column({ length: 500, nullable: true })
    avatar?: string;

    // 用户角色
    @Column({
        type: 'enum',
        enum: UserRole,
        default: UserRole.USER
    })
    role!: UserRole;

    // 用户状态
    @Column({
        type: 'enum',
        enum: UserStatus,
        default: UserStatus.ACTIVE
    })
    status!: UserStatus;

    // 关联订单 - 一对多关系
    @OneToMany(() => Order, order => order.user)
    orders!: Order[];

    // 创建时间
    @CreateDateColumn()
    createdAt!: Date;

    // 更新时间
    @UpdateDateColumn()
    updatedAt!: Date;

    // 最后登录时间
    @Column({ type: 'timestamp', nullable: true })
    lastLoginAt?: Date;

    // 邮箱验证状态
    @Column({ default: false })
    emailVerified!: boolean;

    // 软删除标记
    @Column({ default: false })
    isDeleted!: boolean;

    // 插入前钩子 - 设置默认值
    @BeforeInsert()
    beforeInsert() {
        if (!this.id) {
            this.id = this.generateUUID();
        }
    }

    // 更新前钩子 - 更新时间戳
    @BeforeUpdate()
    beforeUpdate() {
        this.updatedAt = new Date();
    }

    // 生成 UUID 的辅助方法
    private generateUUID(): string {
        return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
            const r = Math.random() * 16 | 0;
            const v = c === 'x' ? r : (r & 0x3 | 0x8);
            return v.toString(16);
        });
    }

    // 转换为安全对象（移除敏感字段）
    toSafeObject() {
        const obj = { ...this };
        delete obj.passwordHash;
        delete obj.isDeleted;
        return obj;
    }
}


