typescript
// userValidation.ts
// 用户数据验证和转换 - 使用 Joi 进行模式验证

import Joi from 'joi';
import { UserRole, UserStatus } from '../entities/user.entity';

// 创建用户的验证模式
export const createUserSchema = Joi.object({
    username: Joi.string()
        .alphanum()           // 只允许字母和数字
        .min(3)
        .max(30)
        .required()
        .messages({
            'string.min': '用户名至少3个字符',
            'string.max': '用户名最多30个字符',
            'any.required': '用户名不能为空'
        }),

    email: Joi.string()
        .email()
        .required()
        .messages({
            'string.email': '请输入有效的邮箱地址',
            'any.required': '邮箱不能为空'
        }),

    password: Joi.string()
        .min(8)
        .max(128)
        .pattern(new RegExp('^(?=.*[a-z])(?=.*[A-Z])(?=.*\\d)'))
        .required()
        .messages({
            'string.min': '密码至少8个字符',
            'string.pattern.base': '密码必须包含大小写字母和数字',
            'any.required': '密码不能为空'
        }),

    nickname: Joi.string()
        .max(100)
        .allow('', null),

    phone: Joi.string()
        .pattern(/^1[3-9]\\d{9}$/)
        .allow('', null)
        .messages({
            'string.pattern.base': '请输入有效的手机号码'
        }),

    role: Joi.string()
        .valid(...Object.values(UserRole))
        .default(UserRole.USER)
});

// 更新用户的验证模式（部分字段可选）
export const updateUserSchema = Joi.object({
    nickname: Joi.string().max(100).allow('', null),
    phone: Joi.string().pattern(/^1[3-9]\d{9}$/).allow('', null),
    avatar: Joi.string().uri().max(500).allow('', null),
    status: Joi.string().valid(...Object.values(UserStatus)),
    emailVerified: Joi.boolean()
}).min(1).messages({
    'object.min': '至少需要提供一个要更新的字段'
});

// 登录验证模式
export const loginSchema = Joi.object({
    identifier: Joi.string().required().messages({
        'any.required': '请输入用户名或邮箱'
    }),
    password: Joi.string().required().messages({
        'any.required': '请输入密码'
    })
});

// 验证结果类型定义
export interface ValidationResult<T = unknown> {
    success: boolean;
    data?: T;
    error?: {
        field: string;
        message: string;
    }[];
}

// 通用验证函数
export function validate<T>(
    schema: Joi.ObjectSchema,
    data: unknown
): ValidationResult<T> {
    const { error, value } = schema.validate(data, {
        abortEarly: false,     // 返回所有错误而非第一个
        stripUnknown: true     // 移除未知字段
    });

    if (error) {
        return {
            success: false,
            error: error.details.map(detail => ({
                field: detail.path.join('.'),
                message: detail.message
            }))
        };
    }

    return {
        success: true,
        data: value as T
    };
}

// 数据转换函数 - 将请求数据转换为实体格式
export function transformUserData(rawData: CreateUserInput): CreateUserEntity {
    return {
        username: rawData.username.toLowerCase().trim(),
        email: rawData.email.toLowerCase().trim(),
        passwordHash: hashPassword(rawData.password),
        nickname: rawData.nickname?.trim(),
        phone: rawData.phone,
        role: rawData.role || UserRole.USER,
        status: UserStatus.ACTIVE,
        emailVerified: false,
        createdAt: new Date()
    };
}

// 密码哈希函数（实际项目中应使用 bcrypt）
function hashPassword(password: string): string {
    // 演示用，实际应使用: await bcrypt.hash(password, 10)
    const crypto = require('crypto');
    return crypto.createHash('sha256').update(password).digest('hex');
}

// 类型定义
export interface CreateUserInput {
    username: string;
    email: string;
    password: string;
    nickname?: string;
    phone?: string;
    role?: UserRole;
}

export interface CreateUserEntity {
    username: string;
    email: string;
    passwordHash: string;
    nickname?: string;
    phone?: string;
    role: UserRole;
    status: UserStatus;
    emailVerified: boolean;
    createdAt: Date;
}


### 示例四：业务规则与流程控制代码

**场景**：实现订单处理的业务规则

typescript
// orderService.ts
// 订单服务 - 包含业务规则和流程控制

import { Injectable } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository, Between, In } from 'typeorm';
import { Order, OrderStatus } from '../entities/order.entity';
import { Product } from '../entities/product.entity';
import { InventoryService } from './inventoryService';

// 业务异常类
class BusinessException extends Error {
    constructor(
        message: string,
        public code: string,
        public statusCode: number = 400
    ) {
        super(message);
        this.name = 'BusinessException';
    }
}

// 订单创建 DTO
interface CreateOrderDto {
    userId: string;
    items: Array<{
        productId: string;
        quantity: number;
    }>;
    shippingAddress: string;
    paymentMethod: 'wechat' | 'alipay' | 'card';
}

@Injectable()
export class OrderService {
    constructor(
        @InjectRepository(Order)
        private readonly orderRepository: Repository<Order>,
        @InjectRepository(Product)
        private readonly productRepository: Repository<Product>,
        private readonly inventoryService: InventoryService
    ) {}

    /**
     * 创建订单 - 完整的业务规则处理
     */
    async createOrder(dto: CreateOrderDto): Promise<Order> {
        // 规则1: 验证用户状态
        const user = await this.validateUserStatus(dto.userId);

        // 规则2: 验证商品信息并计算价格
        const { items, totalAmount } = await this.validateAndCalculateOrderItems(dto.items);

        // 规则3: 验证库存
        await this.validateInventory(items);

        // 规则4: 应用业务规则（折扣、优惠券等）
        const finalAmount = await this.applyBusinessRules(user, totalAmount, dto);

        // 规则5: 锁定库存
        await this.lockInventory(items);

        // 规则6: 创建订单
        const order = this.orderRepository.create({
            orderNo: this.generateOrderNo(),
            userId: dto.userId,
            items: items.map(item => ({
                productId: item.product.id,
                productName: item.product.name,
                price: item.product.price,
                quantity: item.quantity,
                subtotal: item.product.price * item.quantity
            })),
            totalAmount,
            finalAmount,
            discount: totalAmount - finalAmount,
            shippingAddress: dto.shippingAddress,
            paymentMethod: dto.paymentMethod,
            status: OrderStatus.PENDING_PAYMENT,
            // 自动设置过期时间（15分钟）
            expireAt: new Date(Date.now() + 15 * 60 * 1000)
        });

        const savedOrder = await this.orderRepository.save(order);

        // 规则7: 发送通知
        await this.sendOrderCreatedNotification(savedOrder);

        return savedOrder;
    }

    /**
     * 订单状态流转控制
     */
    async updateOrderStatus(
        orderId: string,
        newStatus: OrderStatus,
        operatorId?: string
    ): Promise<Order> {
        const order = await this.orderRepository.findOne({
            where: { id: orderId },
            lock: { mode: 'pessimistic_write' }  // 悲观锁防止并发
        });

        if (!order) {
            throw new BusinessException('订单不存在', 'ORDER_NOT_FOUND', 404);
        }

        // 定义允许的状态流转
        const allowedTransitions: Record<OrderStatus, OrderStatus[]> = {
            [OrderStatus.PENDING_PAYMENT]: [
                OrderStatus.CANCELLED,
                OrderStatus.PAID
            ],
            [OrderStatus.PAID]: [
                OrderStatus.CONFIRMED,
                OrderStatus.REFUNDED
            ],
            [OrderStatus.CONFIRMED]: [
                OrderStatus.SHIPPED,
                OrderStatus.REFUNDED
            ],
            [OrderStatus.SHIPPED]: [
                OrderStatus.DELIVERED,
                OrderStatus.REFUNDED
            ],
            [OrderStatus.DELIVERED]: [
                OrderStatus.COMPLETED,
                OrderStatus.REFUNDED
            ],
            [OrderStatus.COMPLETED]: [],
            [OrderStatus.CANCELLED]: [],
            [OrderStatus.REFUNDED]: []
        };

        // 验证状态流转是否合法
        if (!allowedTransitions[order.status].includes(newStatus)) {
            throw new BusinessException(
                `不允许从 ${order.status} 直接转为 ${newStatus}`,
                'INVALID_STATUS_TRANSITION',
                400
            );
        }

        // 执行状态流转
        const previousStatus = order.status;
        order.status = newStatus;
        order.updatedAt = new Date();

        // 状态特定的处理逻辑
        switch (newStatus) {
            case OrderStatus.PAID:
                order.paidAt = new Date();
                break;
            case OrderStatus.SHIPPED:
                order.shippedAt = new Date();
                break;
            case OrderStatus.DELIVERED:
                order.deliveredAt = new Date();
                break;
            case OrderStatus.COMPLETED:
                await this.unlockInventory(order);  // 完成后释放锁定
                await this.updateUserPurchaseStats(order.userId);
                break;
            case OrderStatus.CANCELLED:
                await this.unlockInventory(order);  // 取消后释放库存
                break;
            case OrderStatus.REFUNDED:
                await this.unlockInventory(order);
                await this.processRefund(order);
                break;
        }

        const updatedOrder = await this.orderRepository.save(order);

        // 发送状态变更通知
        await this.sendStatusChangeNotification(updatedOrder, previousStatus);

        return updatedOrder;
    }

    /**
     * 自动取消过期未支付订单
     */
    @Cron('*/5 * * * *')  // 每5分钟执行
    async cancelExpiredOrders(): Promise<void> {
        const expiredOrders = await this.orderRepository.find({
            where: {
                status: OrderStatus.PENDING_PAYMENT,
                expireAt: LessThanOrEqual(new Date())
            }
        });

        for (const order of expiredOrders) {
            try {
                await this.updateOrderStatus(order.id, OrderStatus.CANCELLED);
                console.log(`订单 ${order.orderNo} 已自动取消`);
            } catch (error) {
                console.error(`取消订单 ${order.orderNo} 失败:`, error);
            }
        }
    }

    // ========== 私有辅助方法 ==========

    private async validateUserStatus(userId: string) {
        // 验证用户是否存在且状态正常
        const user = await this.userRepository.findOne({ where: { id: userId } });
        if (!user) {
            throw new BusinessException('用户不存在', 'USER_NOT_FOUND', 404);
        }
        if (user.status !== UserStatus.ACTIVE) {
            throw new BusinessException('用户账号状态异常', 'USER_INACTIVE', 403);
        }
        return user;
    }

    private async validateAndCalculateOrderItems(
        items: CreateOrderDto['items']
    ): Promise<{ items: Array<{ product: Product; quantity: number }>; totalAmount: number }> {
        if (!items || items.length === 0) {
            throw new BusinessException('订单至少包含一个商品', 'EMPTY_ORDER');
        }

        const validatedItems: Array<{ product: Product; quantity: number }> = [];
        let totalAmount = 0;

        for (const item of items) {
            const product = await this.productRepository.findOne({
                where: { id: item.productId, isActive: true }
            });

            if (!product) {
                throw new BusinessException(
                    `商品 ${item.productId} 不存在或已下架`,
                    'PRODUCT_NOT_FOUND'
                );
            }

            if (product.stock < item.quantity) {
                throw new BusinessException(
                    `商品 ${product.name} 库存不足，当前库存: ${product.stock}`,
                    'INSUFFICIENT_STOCK'
                );
            }

            validatedItems.push({ product, quantity: item.quantity });
            totalAmount += product.price * item.quantity;
        }

        return { items: validatedItems, totalAmount };
    }

    private generateOrderNo(): string {
        const timestamp = Date.now().toString(36);
        const random = Math.random().toString(36).substring(2, 8);
        return `ORD${timestamp}${random}`.toUpperCase();
    }

    private async applyBusinessRules(
        user: User,
        totalAmount: number,
        dto: CreateOrderDto
    ): Promise<number> {
        let finalAmount = totalAmount;

        // 规则: 新用户首单立减10元
        if (user.orderCount === 0) {
            finalAmount = Math.max(0, finalAmount - 10);
        }

        // 规则: 满100元减10元
        if (finalAmount >= 100) {
            finalAmount -= 10;
        }

        // 规则: VIP用户享受95折
        if (user.role === UserRole.VIP) {
            finalAmount *= 0.95;
        }

        return Math.round(finalAmount * 100) / 100;  // 保留两位小数
    }

    private async validateInventory(
        items: Array<{ product: Product; quantity: number }>
    ): Promise<void> {
        for (const item of items) {
            const available = await this.inventoryService.checkAvailability(
                item.product.id,
                item.quantity
            );
            if (!available) {
                throw new BusinessException(
                    `商品 ${item.product.name} 库存不足`,
                    'INSUFFICIENT_INVENTORY'
                );
            }
        }
    }

    private async lockInventory(
        items: Array<{ product: Product; quantity: number }>
    ): Promise<void> {
        for (const item of items) {
            await this.inventoryService.lock(
                item.product.id,
                item.quantity,
                'order_created'
            );
        }
