        .optional()
        .min(16, '年龄不能小于16岁')
        .max(120, '请输入有效的年龄'),

    // 同意条款: 必填且必须为 true
    agreeTerms: Yup.boolean()
        .required('请阅读并同意服务条款')
        .oneOf([true], '请阅读并同意服务条款')
});

// 登录验证模式
const loginSchema = Yup.object().shape({
    // 支持用户名或邮箱登录
    account: Yup.string()
        .required('请输入用户名或邮箱')
        .test(
            'is-valid-account',
            '请输入有效的用户名或邮箱',
            (value) => {
                if (!value) return false;
                const isEmail = /^[\\S]+@[\\S]+\\.[\\S]+$/.test(value);
                const isUsername = /^[a-zA-Z0-9_]{3,20}$/.test(value);
                return isEmail || isUsername;
            }
        ),

    password: Yup.string()
        .required('请输入密码')
        .min(1, '密码不能为空')
});

// 数据转换函数
const transformRegisterData = async (rawData: unknown) => {
    // 1. 验证数据
    const validatedData = await registerSchema.validate(rawData, {
        abortEarly: false,
        stripUnknown: true
    });

    // 2. 标准化数据格式
    const normalizedData = {
        username: validatedData.username.toLowerCase().trim(),
        email: validatedData.email.toLowerCase().trim(),
        password: validatedData.password,
        phone: validatedData.phone || null,
        age: validatedData.age || null,
        agreeTerms: validatedData.agreeTerms,
        agreeTermsAt: validatedData.agreeTerms ? new Date() : null,
        createdAt: new Date(),
        updatedAt: new Date(),
        status: 'active'
    };

    // 3. 生成唯一标识符
    const salt = await bcrypt.genSalt(10);
    normalizedData.password = await bcrypt.hash(normalizedData.password, salt);
    normalizedData.userId = generateUUID();

    // 4. 设置默认值
    normalizedData.emailVerified = false;
    normalizedData.lastLoginAt = null;
    normalizedData.loginCount = 0;
    normalizedData.role = 'user';

    return normalizedData;
};

// 验证辅助函数
const validateField = async (
    fieldName: string,
    value: unknown
): Promise<{ isValid: boolean; error?: string }> => {
    const fieldSchema = Yup.reach(registerSchema, fieldName);

    try {
        await fieldSchema.validate(value);
        return { isValid: true };
    } catch (error) {
        if (error instanceof Yup.ValidationError) {
            return { isValid: false, error: error.message };
        }
        return { isValid: false, error: '验证失败' };
    }
};

// 批量验证函数
const validateMultipleFields = async (
    data: Record<string, unknown>
): Promise<{
    success: boolean;
    errors: Record<string, string>;
    validData?: Record<string, unknown>
}> => {
    try {
        const validData = await registerSchema.validate(data, {
            abortEarly: false,
            stripUnknown: true
        });
        return { success: true, errors: {}, validData };
    } catch (error) {
        if (error instanceof Yup.ValidationError) {
            const errors: Record<string, string> = {};
            error.inner.forEach((err) => {
                if (err.path) {
                    errors[err.path] = err.message;
                }
            });
            return { success: false, errors };
        }
        return { success: false, errors: { general: '验证失败' } };
    }
};

export {
    registerSchema,
    loginSchema,
    transformRegisterData,
    validateField,
    validateMultipleFields
};

