# 待测试的源代码 - orderService.py
from dataclasses import dataclass
from typing import Protocol
from datetime import datetime

# 定义协议（接口）
class PaymentGateway(Protocol):
    def process_payment(self, amount: float) -> bool:
        ...

class EmailService(Protocol):
    def send_confirmation(self, email: str, message: str) -> None:
        ...

@dataclass
class Order:
    order_id: str
    items: list[dict]
    total_amount: float
    customer_email: str

class OrderService:
    def __init__(self, payment_gateway: PaymentGateway, email_service: EmailService):
        self.payment_gateway = payment_gateway
        self.email_service = email_service
        self.orders: list[Order] = []

    def create_order(self, items: list[dict], total_amount: float, customer_email: str) -> dict:
        # 处理支付
        payment_success = self.payment_gateway.process_payment(total_amount)

        if not payment_success:
            return {
                'success': False,
                'message': '支付失败'
            }

        # 创建订单
        order = Order(
            order_id=f'ORD-{datetime.now().timestamp()}',
            items=items,
            total_amount=total_amount,
            customer_email=customer_email
        )
        self.orders.append(order)

        # 发送确认邮件
        self.email_service.send_confirmation(
            customer_email,
            f'您的订单 {order.order_id} 已创建，金额：{total_amount}元'
        )

        return {
            'success': True,
            'order_id': order.order_id,
            'message': '订单创建成功'
        }

