// JavaScript 单元测试示例 - 折扣计算函数
// 待测试函数
function calculateDiscount(originalPrice, discountPercent) {
  if (originalPrice < 0) {
    throw new Error('原价不能为负数');
  }
  if (discountPercent < 0 || discountPercent > 100) {
    throw new Error('折扣百分比必须在0-100之间');
  }
  return originalPrice * (1 - discountPercent / 100);
}

// Copilot 生成的 Jest 测试
describe('calculateDiscount 函数测试', () => {
  test('正常折扣：100元打9折应返回90元', () => {
    expect(calculateDiscount(100, 10)).toBe(90);
  });

  test('无折扣：100元不打折应返回100元', () => {
    expect(calculateDiscount(100, 0)).toBe(100);
  });

  test('原价为零应返回零', () => {
    expect(calculateDiscount(0, 50)).toBe(0);
  });

  test('小数价格计算正确', () => {
    expect(calculateDiscount(99.99, 15)).toBeCloseTo(84.9915);
  });

  test('负数原价应抛出错误', () => {
    expect(() => calculateDiscount(-10, 20)).toThrow('原价不能为负数');
  });

  test('折扣为负数应抛出错误', () => {
    expect(() => calculateDiscount(100, -10)).toThrow('折扣百分比必须在0-100之间');
  });

  test('折扣超过100%应抛出错误', () => {
    expect(() => calculateDiscount(100, 150)).toThrow('折扣百分比必须在0-100之间');
  });

  test('折扣为100%应返回0', () => {
    expect(calculateDiscount(100, 100)).toBe(0);
  });
});
