// 示例1：代码坏味道识别与重构 - 过长函数重构
// 重构前：包含多个职责的过长函数
function processOrder(order) {
    // 验证订单
    if (!order.items || order.items.length === 0) {
        return { success: false, error: '订单不能为空' };
    }
    for (let item of order.items) {
        if (item.quantity <= 0) {
            return { success: false, error: '商品数量必须大于0' };
        }
    }

    // 计算价格
    let total = 0;
    for (let item of order.items) {
        total += item.price * item.quantity;
    }
    if (order.discount) {
        total = total * (1 - order.discount);
    }

    // 应用税费
    total = total * 1.1;

    // 保存订单
    const orderRecord = {
        id: generateOrderId(),
        items: order.items,
        total: total,
        createdAt: new Date()
    };
    saveToDatabase(orderRecord);

    // 发送确认邮件
    sendEmail(order.customerEmail, '订单确认', '您的订单已处理');

    // 更新库存
    for (let item of order.items) {
        updateInventory(item.productId, item.quantity);
    }

    return { success: true, orderId: orderRecord.id, total: total };
}

// 重构后：职责分离的清晰代码
class OrderProcessor {
    constructor(orderValidator, priceCalculator, orderRepository, notificationService) {
        this.validator = orderValidator;
        this.priceCalculator = priceCalculator;
        this.repository = orderRepository;
        this.notificationService = notificationService;
    }

    process(order) {
        // 验证订单（单一职责）
        const validationResult = this.validator.validate(order);
        if (!validationResult.isValid) {
            return { success: false, error: validationResult.error };
        }

        // 计算价格（单一职责）
        const total = this.priceCalculator.calculate(order);

        // 保存订单（单一职责）
        const orderRecord = this.createOrderRecord(order, total);
        this.repository.save(orderRecord);

        // 通知相关方（单一职责）
        this.notificationService.sendOrderConfirmation(order, orderRecord);

        return { success: true, orderId: orderRecord.id, total };
    }

    createOrderRecord(order, total) {
        return {
            id: generateOrderId(),
            items: order.items,
            total,
            createdAt: new Date()
        };
    }
}

