// 示例2：设计模式应用 - 策略模式重构if-else链
// 重构前：复杂的支付方式判断
class PaymentProcessor {
    processPayment(order, paymentType) {
        if (paymentType === 'credit_card') {
            // 处理信用卡支付
            const cardProcessor = new CreditCardProcessor();
            cardProcessor.validateCard(order.cardNumber);
            cardProcessor.charge(order.amount);
            return { success: true, type: 'credit_card' };
        } else if (paymentType === 'debit_card') {
            // 处理借记卡支付
            const debitProcessor = new DebitCardProcessor();
            debitProcessor.validateCard(order.cardNumber);
            debitProcessor.charge(order.amount);
            return { success: true, type: 'debit_card' };
        } else if (paymentType === 'paypal') {
            // 处理PayPal支付
            const paypalProcessor = new PayPalProcessor();
            paypalProcessor.authenticate(order.paypalAccount);
            paypalProcessor.pay(order.amount);
            return { success: true, type: 'paypal' };
        } else if (paymentType === 'bank_transfer') {
            // 处理银行转账
            const bankProcessor = new BankTransferProcessor();
            bankProcessor.validateAccount(order.bankAccount);
            bankProcessor.transfer(order.amount);
            return { success: true, type: 'bank_transfer' };
        } else {
            throw new Error('不支持的支付方式');
        }
    }
}

// 重构后：使用策略模式
// 策略接口
class PaymentStrategy {
    process(paymentInfo) {
        throw new Error('必须实现process方法');
    }
}

// 具体策略实现
class CreditCardStrategy extends PaymentStrategy {
    process(paymentInfo) {
        const processor = new CreditCardProcessor();
        processor.validateCard(paymentInfo.cardNumber);
        processor.charge(paymentInfo.amount);
        return { success: true, type: 'credit_card' };
    }
}

class PayPalStrategy extends PaymentStrategy {
    process(paymentInfo) {
        const processor = new PayPalProcessor();
        processor.authenticate(paymentInfo.paypalAccount);
        processor.pay(paymentInfo.amount);
        return { success: true, type: 'paypal' };
    }
}

class BankTransferStrategy extends PaymentStrategy {
    process(paymentInfo) {
        const processor = new BankTransferProcessor();
        processor.validateAccount(paymentInfo.bankAccount);
        processor.transfer(paymentInfo.amount);
        return { success: true, type: 'bank_transfer' };
    }
}

// 策略工厂
class PaymentStrategyFactory {
    static strategies = {
        'credit_card': new CreditCardStrategy(),
        'paypal': new PayPalStrategy(),
        'bank_transfer': new BankTransferStrategy()
    };

    static getStrategy(paymentType) {
        const strategy = this.strategies[paymentType];
        if (!strategy) {
            throw new Error(`不支持的支付方式: ${paymentType}`);
        }
        return strategy;
    }
}

// 重构后的处理器
class PaymentProcessorRefactored {
    processPayment(order, paymentType) {
        const strategy = PaymentStrategyFactory.getStrategy(paymentType);
        return strategy.process({
            amount: order.amount,
            cardNumber: order.cardNumber,
            paypalAccount: order.paypalAccount,
            bankAccount: order.bankAccount
        });
    }
}

