function ProductListOptimized({ products, category }) {
    // 使用useMemo缓存过滤结果，只有products或category变化时才重新计算
    const filteredProducts = useMemo(() => {
        return products.filter(product => 
            product.category.toLowerCase().startsWith(category.toLowerCase()) && 
            product.inStock
        );
    }, [products, category]);

    // 使用useMemo缓存计算结果
