    setValues(initialValues);
    setErrors({});
  }, [initialValues]);

  // 设置错误
  const setFieldError = useCallback((field, message) => {
    setErrors(prev => ({
      ...prev,
      [field]: message
    }));
  }, []);

  return {
    values,
    errors,
    handleChange,
    reset,
    setFieldError,
    setValues
  };
}

