```python
// 示例 2：跨文件协作 - 实现通知系统的模块化
// 场景：通知系统需要支持多种渠道（邮件、短信、推送），但要保持统一接口

// src/shared/interfaces/notification.interface.ts
/**
 * 通知渠道接口
 * 定义所有通知渠道必须实现的方法
 */
export interface INotificationChannel {
  /** 渠道名称，用于日志和配置 */
  readonly name: string;

  /** 发送通知，返回是否成功 */
  send(recipient: NotificationRecipient, content: NotificationContent): Promise<NotificationResult>;

  /** 验证接收者是否有效 */
  validateRecipient(recipient: NotificationRecipient): Promise<boolean>;
}

export interface NotificationRecipient {
  userId: string;
  email?: string;      // 邮件渠道需要
  phone?: string;       // 短信渠道需要
  deviceToken?: string; // 推送渠道需要
}

export interface NotificationContent {
  subject: string;
  body: string;
  templateId?: string;
  templateData?: Record<string, unknown>;
}

export interface NotificationResult {
  success: boolean;
  messageId?: string;
  error?: string;
  timestamp: Date;
}

// src/modules/notifications/channels/email.channel.ts
/**
 * 邮件通知渠道实现
 * Copilot 会根据 INotificationChannel 接口生成符合规范的实现
 */
export class EmailNotificationChannel implements INotificationChannel {
  readonly name = 'email';

  constructor(
    private readonly emailClient: IEmailClient,
    private readonly templateEngine: ITemplateEngine
  ) {}

  async send(recipient: NotificationRecipient, content: NotificationContent): Promise<NotificationResult> {
    if (!recipient.email) {
      return {
        success: false,
        error: 'Email address not provided',
        timestamp: new Date()
      };
    }

    try {
      let body = content.body;

      // 如果有模板，使用模板引擎渲染
      if (content.templateId && content.templateData) {
        body = await this.templateEngine.render(
          content.templateId,
          content.templateData
        );
      }

      const messageId = await this.emailClient.send({
        to: recipient.email,
        subject: content.subject,
        html: body
      });

      return {
        success: true,
        messageId,
        timestamp: new Date()
      };
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Unknown error',
        timestamp: new Date()
      };
    }
  }

  async validateRecipient(recipient: NotificationRecipient): Promise<boolean> {
    return !!recipient.email && this.isValidEmail(recipient.email);
  }

  private isValidEmail(email: string): boolean {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }
}

// src/modules/notifications/notification.service.ts
/**
 * 通知服务 - 协调多个渠道
 * 根据优先级和用户偏好选择合适的通知渠道
 */
export class NotificationService {
  private channels: Map<string, INotificationChannel> = new Map();

  constructor(
    private readonly userService: IUserService,  // 依赖用户服务获取联系信息
    private readonly logger: ILogger
  ) {}

  /** 注册通知渠道 */
  registerChannel(channel: INotificationChannel): void {
    this.channels.set(channel.name, channel);
    this.logger.info(`Notification channel registered: ${channel.name}`);
  }

  /** 发送通知给用户 */
  async notifyUser(
    userId: string,
    content: NotificationContent,
    preferences?: UserNotificationPreferences
  ): Promise<NotificationResult[]> {
    const results: NotificationResult[] = [];

    // 获取用户信息，包括各渠道的联系信息
    const user = await this.userService.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    // 构建接收者对象
    const recipient: NotificationRecipient = {
      userId,
      email: user.email,
      phone: user.phone,
      deviceToken: user.deviceToken
    };

    // 根据用户偏好决定使用哪些渠道
    const enabledChannels = preferences?.enabledChannels || ['email'];

    for (const channelName of enabledChannels) {
      const channel = this.channels.get(channelName);
      if (!channel) {
        this.logger.warn(`Channel not found: ${channelName}`);
        continue;
      }

      // 验证接收者是否有效
      const isValid = await channel.validateRecipient(recipient);
      if (!isValid) {
        this.logger.warn(`Invalid recipient for channel ${channelName}`);
        continue;
      }

      // 发送通知
      const result = await channel.send(recipient, content);
      results.push(result);

      this.logger.info(
        `Notification ${result.success ? 'sent' : 'failed'} via ${channelName}`
      );
    }

    return results;
  }

  /** 广播通知给多个用户 */
  async broadcast(
    userIds: string[],
    content: NotificationContent
  ): Promise<Map<string, NotificationResult[]>> {
    const results = new Map<string, NotificationResult[]>();

    // 批量处理，使用 Promise.all 提升性能
    const promises = userIds.map(async (userId) => {
      const userResults = await this.notifyUser(userId, content);
      return { userId, results: userResults };
    });

    const resolved = await Promise.all(promises);
    resolved.forEach(({ userId, results: userResults }) => {
      results.set(userId, userResults);
    });

    return results;
  }
}

