export class UserService implements IUserService {
  constructor(
    private readonly userRepository: IUserRepository,  // 通过构造函数注入
    private readonly emailService: IEmailService,      // 依赖其他服务
    private readonly eventBus: IEventBus               // 事件总线用于解耦
  ) {}

  async findById(id: string): Promise<User | null> {
    return this.userRepository.findById(id);
  }

  async create(data: CreateUserDto): Promise<User> {
    // 业务逻辑：检查邮箱唯一性
    const existing = await this.userRepository.findByEmail(data.email);
    if (existing) {
      throw new UserAlreadyExistsError(data.email);
    }

    // 创建用户（密码会被加密）
    const user = User.create(data);
    const savedUser = await this.userRepository.create(user);

    // 发布用户创建事件，供其他模块订阅
    this.eventBus.publish(new UserCreatedEvent(savedUser));

    return savedUser;
  }

  async resetPassword(id: string): Promise<string> {
    const user = await this.userRepository.findById(id);
    if (!user) {
      throw new UserNotFoundError(id);
    }

    const tempPassword = this.generateTempPassword();
    user.resetPassword(tempPassword);
    await this.userRepository.update(id, { password: user.password });

    // 发送临时密码到用户邮箱
    await this.emailService.sendPasswordResetEmail(user.email, tempPassword);

    return tempPassword;
  }

  private generateTempPassword(): string {
    // 生成临时密码的逻辑
    return crypto.randomBytes(8).toString('hex');
  }
}

