// 团队 Copilot 配置管理示例
// 文件：team-copilot-config.js

class TeamCopilotConfigManager {
  constructor() {
    this.configs = new Map();
    this.defaultConfig = this.getDefaultConfig();
  }

  // 获取默认配置
  getDefaultConfig() {
    return {
      // 代码补全设置
      completion: {
        maxTokens: 1500,
        temperature: 0.7,
        topP: 0.95,
        frequencyPenalty: 0,
        presencePenalty: 0,
      },
      // 安全设置
      security: {
        scanSecrets: true,
        validateInputs: true,
        requireAuth: true,
      },
      // 文档设置
      documentation: {
        requireJsDoc: true,
        minCoverage: 80,
        autoGenerate: true,
      },
      // 代码风格
      style: {
        indentSize: 2,
        useSemicolons: true,
        quoteStyle: 'single',
        lineLength: 100,
      },
    };
  }

  // 注册团队配置
  registerTeam(teamName, customConfig = {}) {
    const config = {
      ...this.defaultConfig,
      ...customConfig,
      teamName,
      createdAt: new Date().toISOString(),
    };
    this.configs.set(teamName, config);
    return config;
  }

  // 获取团队配置
  getTeamConfig(teamName) {
    return this.configs.get(teamName) || this.defaultConfig;
  }

  // 应用配置到 IDE
  async applyConfig(teamName, ideAdapter) {
    const config = this.getTeamConfig(teamName);
    await ideAdapter.applySettings({
      completion: config.completion,
      security: config.security,
      documentation: config.documentation,
      style: config.style,
    });
    console.log(`配置已应用到团队 ${teamName}`);
    return true;
  }

  // 验证配置有效性
  validateConfig(config) {
    const errors = [];

    if (config.completion?.temperature < 0 || config.completion?.temperature > 1) {
      errors.push('temperature 必须在 0-1 之间');
    }
    if (config.style?.indentSize < 1 || config.style?.indentSize > 8) {
      errors.push('indentSize 必须在 1-8 之间');
    }

    return {
      valid: errors.length === 0,
      errors,
    };
  }
}

