javascript
// 提示库管理系统
// 文件：prompt-library.js

class PromptLibrary {
  constructor() {
    this.prompts = new Map();
    this.categories = new Set();
    this.versionHistory = [];
  }

  // 添加提示词
  addPrompt(prompt) {
    const id = this.generatePromptId(prompt);
    const promptData = {
      id: id,
      ...prompt,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      usageCount: 0,
      successRate: 0,
    };

    this.prompts.set(id, promptData);
    this.categories.add(prompt.category);

    this.logChange('add', id);

    return promptData;
  }

  // 更新提示词
  updatePrompt(id, updates) {
    const existing = this.prompts.get(id);
    if (!existing) {
      throw new Error(`提示词 ${id} 不存在`);
    }

    const previous = { ...existing };
    const updated = {
      ...existing,
      ...updates,
      updatedAt: new Date().toISOString(),
      version: (existing.version || 0) + 1,
    };

    this.prompts.set(id, updated);
    this.versionHistory.push({
      action: 'update',
      promptId: id,
      previous: previous,
      current: updated,
      timestamp: new Date().toISOString(),
    });

    return updated;
  }

  // 获取提示词
  getPrompt(id) {
    const prompt = this.prompts.get(id);
    if (prompt) {
      prompt.usageCount++;
    }
    return prompt;
  }

  // 按类别搜索
  searchByCategory(category) {
    const results = [];
    for (const prompt of this.prompts.values()) {
      if (prompt.category === category) {
        results.push(prompt);
      }
    }
    return results;
  }

  // 全文搜索
  search(query) {
    const results = [];
    const lowerQuery = query.toLowerCase();

    for (const prompt of this.prompts.values()) {
      const searchableText = `
        ${prompt.name} 
        ${prompt.description} 
        ${prompt.content} 
        ${prompt.tags?.join(' ') || ''}
      `.toLowerCase();

      if (searchableText.includes(lowerQuery)) {
        results.push({
          ...prompt,
          relevanceScore: this.calculateRelevance(searchableText, lowerQuery),
        });
      }
    }

    return results.sort((a, b) => b.relevanceScore - a.relevanceScore);
  }

  // 计算相关性得分
  calculateRelevance(text, query) {
    let score = 0;
    const words = query.split(' ');

    for (const word of words) {
      if (text.includes(word)) {
        score += 1;
      }
    }

    return score;
  }

  // 记录使用效果
  recordUsage(promptId, result) {
    const prompt = this.prompts.get(promptId);
    if (!prompt) return;

    prompt.usageHistory = prompt.usageHistory || [];
    prompt.usageHistory.push({
      timestamp: new Date().toISOString(),
      success: result.success,
      feedback: result.feedback,
    });

    // 计算新的成功率
    const successful = prompt.usageHistory.filter(u => u.success).length;
    prompt.successRate = (successful / prompt.usageHistory.length) * 100;
  }

  // 获取推荐提示词
  getRecommendations(context) {
    const recommendations = [];

    for (const prompt of this.prompts.values()) {
      const score = this.matchContext(prompt, context);
      if (score > 0.5) {
        recommendations.push({
          ...prompt,
          matchScore: score,
        });
      }
    }

    return recommendations
      .sort((a, b) => b.matchScore - a.matchScore)
      .slice(0, 5);
  }

  // 匹配上下文
  matchContext(prompt, context) {
    let score = 0;

    // 匹配语言
    if (prompt.language === context.language) {
      score += 0.3;
    }

    // 匹配标签
    const commonTags = (prompt.tags || []).filter(tag => 
      (context.tags || []).includes(tag)
    );
    score += commonTags.length * 0.15;

    // 匹配使用场景
    if (prompt.useCases?.includes(context.useCase)) {
      score += 0.25;
    }

    // 考虑成功率
    score *= (prompt.successRate / 100);

    return score;
  }

  // 导出提示库
  export(format = 'json') {
    return {
      prompts: Array.from(this.prompts.values()),
      categories: Array.from(this.categories),
      exportedAt: new Date().toISOString(),
      version: '1.0',
    };
  }

  // 从文件导入
  import(data) {
    for (const prompt of data.prompts) {
      this.addPrompt(prompt);
    }
  }

  // 生成唯一ID
  generatePromptId(prompt) {
    const timestamp = Date.now();
    const hash = prompt.name
      .toLowerCase()
      .replace(/\s+/g, '_');
    return `prompt_${hash}_${timestamp}`;
  }

  // 记录变更
  logChange(action, id) {
    console.log(`[${action.toUpperCase()}] 提示词 ${id}`);
  }
}

// 使用示例
