// 代码审查反馈收集系统
// 文件：review-feedback-system.js

class ReviewFeedbackSystem {
  constructor() {
    this.feedback = [];
    this.statistics = {
      totalSuggestions: 0,
      accepted: 0,
      rejected: 0,
      modified: 0,
    };
  }

  // 记录反馈
  recordFeedback(data) {
    const entry = {
      id: this.generateId(),
      timestamp: new Date().toISOString(),
      suggestionId: data.suggestionId,
      suggestionText: data.suggestionText,
      action: data.action,  // 'accept' | 'reject' | 'modify'
      reason: data.reason || null,
      file: data.file,
      userId: data.userId,
    };

    this.feedback.push(entry);
    this.updateStatistics(entry.action);

    return entry;
  }

  // 更新统计数据
  updateStatistics(action) {
    this.statistics.totalSuggestions++;
    switch (action) {
      case 'accept':
        this.statistics.accepted++;
        break;
      case 'reject':
        this.statistics.rejected++;
        break;
      case 'modify':
        this.statistics.modified++;
        break;
    }
  }

  // 获取采纳率
  getAcceptanceRate() {
    if (this.statistics.totalSuggestions === 0) return 0;
    return (this.statistics.accepted / this.statistics.totalSuggestions * 100).toFixed(1);
  }

  // 获取最常见的拒绝原因
  getTopRejectionReasons(limit = 5) {
    const reasons = {};

    for (const entry of this.feedback) {
      if (entry.action === 'reject' && entry.reason) {
        reasons[entry.reason] = (reasons[entry.reason] || 0) + 1;
      }
    }

    return Object.entries(reasons)
      .sort((a, b) => b[1] - a[1])
      .slice(0, limit)
      .map(([reason, count]) => ({ reason, count }));
  }

  // 生成分析报告
  generateReport() {
    return {
      period: {
        start: this.feedback[0]?.timestamp,
        end: this.feedback[this.feedback.length - 1]?.timestamp,
      },
      statistics: this.statistics,
      acceptanceRate: `${this.getAcceptanceRate()}%`,
      topRejectionReasons: this.getTopRejectionReasons(),
      recommendations: this.generateRecommendations(),
    };
  }

  // 生成改进建议
  generateRecommendations() {
    const recommendations = [];
    const rate = parseFloat(this.getAcceptanceRate());

    if (rate < 50) {
      recommendations.push({
        type: 'optimization',
        priority: 'high',
        message: '采纳率较低，建议优化团队提示词模板',
      });
    }

    const topReasons = this.getTopRejectionReasons(1);
    if (topReasons.length > 0) {
      recommendations.push({
        type: 'training',
        priority: 'medium',
        message: `最常见的拒绝原因是：${topReasons[0].reason}，建议组织相关培训`,
      });
    }

    return recommendations;
  }

  // 生成唯一ID
  generateId() {
    return `fb_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`;
  }

  // 导出数据
  export() {
    return JSON.stringify(this.feedback, null, 2);
  }
}

// 使用示例
const system = new ReviewFeedbackSystem();

// 记录多条反馈
system.recordFeedback({
