#!/usr/bin/env python3
"""
依赖安全检查工具
检查项目依赖中的已知漏洞
"""

import subprocess
import json
from pathlib import Path

def check_npm_dependencies():
    """检查 npm 依赖安全性"""
    print("正在检查 npm 依赖...")
    try:
        result = subprocess.run(
            ['npm', 'audit', '--json'],
            capture_output=True,
            text=True,
            timeout=60
        )
        audit_data = json.loads(result.stdout)

        vulnerabilities = audit_data.get('vulnerabilities', {})
        if vulnerabilities:
            print(f"⚠️  发现 {len(vulnerabilities)} 个漏洞:")
            for name, info in vulnerabilities.items():
                print(f"  - {name}: {info.get('title', 'Unknown')}")
        else:
            print("✅ npm 依赖检查通过，无已知漏洞")
    except Exception as e:
        print(f"❌ npm 依赖检查失败: {e}")

def check_python_dependencies():
    """检查 Python 依赖安全性"""
    print("正在检查 Python 依赖...")
    try:
        # 使用 safety 检查已知漏洞
        result = subprocess.run(
            ['safety', 'check', '--json'],
            capture_output=True,
            text=True,
            timeout=60
        )
        if result.returncode != 0:
            vulnerabilities = json.loads(result.stdout)
            print(f"⚠️  发现 {len(vulnerabilities)} 个漏洞:")
            for vuln in vulnerabilities:
                print(f"  - {vuln.get('package')}: {vuln.get('advisory')}")
        else:
            print("✅ Python 依赖检查通过，无已知漏洞")
    except FileNotFoundError:
        print("💡 提示: 请安装 safety 工具 (pip install safety)")
    except Exception as e:
        print(f"❌ Python 依赖检查失败: {e}")

if __name__ == '__main__':
    check_npm_dependencies()
    print("---")
    check_python_dependencies()

