const description = "显示用户基本信息，包含头像、用户名和简介";


#### 示例2：API接口开发模板

python
# 模板名称：Django REST API Endpoint
# 用途：标准化创建Django REST Framework接口

def generate_drf_template(model_name, fields):
    """
    生成Django REST Framework接口的提示模板

    参数:
