# 示例：Python实现的模板配置文件
# 支持YAML格式，便于维护和版本控制

import yaml
from typing import Dict, Any, List
from datetime import datetime

class TemplateConfig:
    """提示模板配置管理"""

    def __init__(self, config_path: str):
        self.config_path = config_path
        self.templates = self._load_config()

    def _load_config(self) -> Dict[str, Any]:
        """加载YAML配置文件"""
        with open(self.config_path, 'r', encoding='utf-8') as f:
            return yaml.safe_load(f)

    def get_template(self, name: str, variables: Dict[str, str] = None) -> str:
        """
        获取模板并填充变量

        参数:
            name: 模板名称
            variables: 变量字典
        """
        template_data = self.templates.get('templates', {}).get(name)
        if not template_data:
            raise ValueError(f"模板 '{name}' 不存在")

        content = template_data['content']

        # 替换变量
        if variables:
            for key, value in variables.items():
                content = content.replace(f'${{{key}}}', value)

        return content

    def list_templates(self) -> List[str]:
        """列出所有模板名称"""
        return list(self.templates.get('templates', {}).keys())

# YAML配置文件示例（templates.yaml）：
# templates:
#   react-functional:
#     name: React函数组件模板
#     category: frontend
#     content: |
#       请创建React函数组件: ${component_name}
#       功能描述: ${description}
#       技术栈: React 18, TypeScript
#   
#   api-endpoint:
#     name: API端点模板
#     category: backend
#     content: |
#       请创建API端点: ${endpoint_path}
#       HTTP方法: ${http_method}
#       功能: ${functionality}

# 使用示例
config = TemplateConfig('templates.yaml')
prompt = config.get_template('react-functional', {
    'component_name': 'ProductCard',
    'description': '展示商品信息卡片，包含图片、标题和价格'
})
print(prompt)
```



## 常见错误

- 模板过于泛化，缺乏具体指导，导致Copilot输出不稳定或质量参差不齐
- 模板过于具体，限制了Copilot的发挥空间，每次输出都需要大量修改
- 模板缺乏版本管理，更新后不知道历史版本是什么样的，难以回溯问题
- 模板命名不清晰，时间久了就忘记某个模板的用途是什么
- 模板数量过多但没有分类，每次查找合适的模板花费的时间比直接写还多
- 忽视模板的维护，模板建立后就束之高阁，从不更新优化
- 变量命名不一致，导致同样的概念在不同模板中使用不同名称，降低复用性
- 模板中包含过多项目特定信息，导致模板难以跨项目复用


## 最佳实践

- 从实际高频场景开始建立模板，不要一开始就追求大而全，随着使用逐步完善
- 为每个模板添加清晰的名称、用途说明和使用示例，便于快速理解和使用
- 遵循分层组织原则，将模板分为通用层、框架层、业务层，提高结构清晰度
- 保持模板简洁明了，核心要素明确，细节适度留白，给予Copilot发挥空间
- 建立定期回顾机制，每个月检查一次模板库，删除不再使用的，优化常用模板
- 使用版本控制管理模板文件，便于追踪变更历史，也方便团队协作
- 为模板分类建立索引系统，可以按技术栈、用途、优先级等多维度检索
- 收集使用反馈，记录每次使用模板后的效果，持续改进模板质量
- 团队成员共享成功的模板，定期组织模板评审会议，推广优秀实践
- 将模板与团队代码规范文档关联，确保模板输出的代码符合团队要求

