            this.issues.push({
                type: 'hardcoded',
                message: '发现硬编码的超时值',
                severity: 'low'
            });
        }

        // 检测安全问题
        if (/eval\(|innerHTML\s*=/.test(code)) {
            this.issues.push({
                type: 'security',
                message: '可能存在安全风险',
                severity: 'high'
            });
        }

