以下是一个实用的 Copilot 使用效率追踪脚本，可以帮助你收集和分析使用数据：

### 示例一：代码完成时间追踪

python
#!/usr/bin/env python3
"""
Copilot 代码完成时间追踪器
用于记录每次代码补全的使用情况

使用方法：
1. 安装：pip install -r requirements.txt
2. 运行：python copilot_tracker.py
3. 查看报告：cat copilot_stats.json
"""

import json
import time
from datetime import datetime
from dataclasses import dataclass, asdict
from typing import List, Optional
from pathlib import Path

@dataclass
class CodeCompletion:
    """代码补全记录"""
    timestamp: str
    language: str
    file_path: str
    suggestion_length: int      # 建议代码行数
    accepted: bool             # 是否采纳
    acceptance_time: float     # 采纳耗时（秒）
    rejected_reason: Optional[str] = None  # 拒绝原因
    quality_score: int = 0     # 质量评分 1-5

class CopilotEfficiencyTracker:
    """Copilot 使用效率追踪器"""

    def __init__(self, data_file: str = "copilot_stats.json"):
        self.data_file = Path(data_file)
        self.completions: List[CodeCompletion] = []
        self._load_data()

    def _load_data(self):
        """加载已有数据"""
        if self.data_file.exists():
            with open(self.data_file, 'r', encoding='utf-8') as f:
                data = json.load(f)
                self.completions = [
                    CodeCompletion(**item) for item in data
                ]

    def _save_data(self):
        """保存数据到文件"""
        with open(self.data_file, 'w', encoding='utf-8') as f:
            json.dump(
                [asdict(c) for c in self.completions],
                f,
                ensure_ascii=False,
                indent=2
            )

    def record_completion(self, completion: CodeCompletion):
        """记录一次代码补全"""
        self.completions.append(completion)
        self._save_data()
        print(f"✅ 已记录：{completion.language} - {completion.file_path}")

    def generate_report(self) -> dict:
        """生成效率报告"""
        if not self.completions:
            return {"message": "暂无数据"}

        total = len(self.completions)
        accepted = sum(1 for c in self.completions if c.accepted)
        avg_quality = sum(c.quality_score for c in self.completions) / total
        avg_time = sum(c.acceptance_time for c in self.completions if c.accepted) / accepted if accepted > 0 else 0

        # 按语言分组统计
        by_language = {}
        for c in self.completions:
            lang = c.language
            if lang not in by_language:
                by_language[lang] = {"total": 0, "accepted": 0, "quality_sum": 0}
            by_language[lang]["total"] += 1
            if c.accepted:
                by_language[lang]["accepted"] += 1
            by_language[lang]["quality_sum"] += c.quality_score

        return {
            "report_date": datetime.now().isoformat(),
            "summary": {
                "total_completions": total,
                "accepted_count": accepted,
                "acceptance_rate": f"{accepted/total*100:.1f}%",
                "average_quality_score": round(avg_quality, 2),
                "average_acceptance_time": round(avg_time, 2),
            },
            "by_language": {
                lang: {
                    "total": stats["total"],
                    "accepted": stats["accepted"],
                    "rate": f"{stats['accepted']/stats['total']*100:.1f}%",
                    "avg_quality": round(stats["quality_sum"]/stats["total"], 2)
                }
                for lang, stats in by_language.items()
            },
            "recommendations": self._generate_recommendations(accepted/total, avg_quality)
        }

    def _generate_recommendations(self, acceptance_rate: float, avg_quality: float) -> List[str]:
        """根据数据生成改进建议"""
        recommendations = []

        if acceptance_rate < 0.3:
            recommendations.append("⚠️ 采纳率偏低，建议：检查提示词是否清晰，项目上下文是否充足")
        elif acceptance_rate > 0.8:
            recommendations.append("✅ 采纳率良好，Copilot 理解力不错，继续保持！")

        if avg_quality < 3:
            recommendations.append("⚠️ 质量评分偏低，建议：仔细审查生成的代码，增加代码审查环节")
        elif avg_quality >= 4:
            recommendations.append("✅ 生成的代码质量较高，可以适当提高信任度")

        return recommendations

# 使用示例
if __name__ == "__main__":
    tracker = CopilotEfficiencyTracker()

    # 模拟记录几次补全
    sample_completions = [
        CodeCompletion(
            timestamp=datetime.now().isoformat(),
            language="python",
            file_path="src/utils.py",
            suggestion_length=15,
            accepted=True,
            acceptance_time=3.5,
            quality_score=4
        ),
        CodeCompletion(
            timestamp=datetime.now().isoformat(),
            language="javascript",
            file_path="src/components/Button.jsx",
            suggestion_length=20,
            accepted=False,
            acceptance_time=0,
            rejected_reason="不满足项目代码风格",
            quality_score=2
        ),
    ]

    # 记录样本数据
    for completion in sample_completions:
        tracker.record_completion(completion)

    # 生成报告
    report = tracker.generate_report()
    print("\n📊 效率报告:")
    print(json.dumps(report, ensure_ascii=False, indent=2))


### 示例二：代码质量自动化检查

javascript
#!/usr/bin/env node
/**
 * Copilot 生成代码质量检查脚本
 * 
 * 功能：
 * 1. 检测代码复杂度
 * 2. 检查潜在 Bug
 * 3. 验证代码风格一致性
 * 4. 生成质量报告
 * 
 * 使用方法：
 * node code-quality-checker.js --file src/ai-generated.js
 */

const fs = require('fs');
const path = require('path');

class CodeQualityChecker {
    constructor(options = {}) {
        this.options = {
            maxComplexity: options.maxComplexity || 10,
            maxLineLength: options.maxLineLength || 120,
            requiredPrefix: options.requiredPrefix || 'ai-generated'
        };
    }

    /**
     * 分析代码复杂度
     * 使用圈复杂度（Cyclomatic Complexity）作为指标
     */
    analyzeComplexity(code) {
        const complexityIndicators = [
            /\bif\b/g,           // if 语句
            /\belse\b/g,         // else 语句
            /\bfor\b/g,          // for 循环
            /\bwhile\b/g,        // while 循环
            /\bcase\b/g,         // switch case
            /\bcatch\b/g,        // 异常捕获
            /\?/g,               // 三元运算符
            /\&\&|\|\|/g         // 逻辑运算符
        ];

        let complexity = 1; // 基础复杂度

        for (const pattern of complexityIndicators) {
            const matches = code.match(pattern);
            if (matches) {
                complexity += matches.length;
            }
        }

        return {
            score: complexity,
            rating: complexity <= 5 ? '🟢 简单' :
                    complexity <= 10 ? '🟡 中等' : '🔴 复杂',
            warning: complexity > this.options.maxComplexity
        };
    }

    /**
     * 检测常见的 Copilot 生成代码问题
     */
    detectCommonIssues(code) {
        const issues = [];

        // 检测 TODO 注释（可能是未完成的代码）
        const todoMatches = code.match(/\/\/\s*TODO|\/\*\s*TODO/g);
        if (todoMatches) {
            issues.push({
                type: 'incomplete',
                severity: 'medium',
                message: `发现 ${todoMatches.length} 处未完成的 TODO`,
                count: todoMatches.length
            });
        }

        // 检测硬编码值
        const hardcodedRegexes = [
            { pattern: /timeout\s*[=:]\s*\d{4,}/g, name: '魔法数字（超时）' },
            { pattern: /retry\s*[=:]\s*[3-9]\d*/g, name: '魔法数字（重试）' },
            { pattern: /\[\s*['"]\w{20,}['"]\s*\]/g, name: '长硬编码字符串' }
        ];

        for (const { pattern, name } of hardcodedRegexes) {
            if (pattern.test(code)) {
                issues.push({
                    type: 'hardcoded',
                    severity: 'low',
                    message: `发现可能的 ${name}`
                });
            }
        }

        // 检测不安全的实践
        const securityIssues = [
            { pattern: /eval\s*\(/g, message: '使用 eval() 可能存在安全风险' },
            { pattern: /innerHTML\s*=/g, message: '直接赋值 innerHTML 可能存在 XSS 风险' },
            { pattern: /password\s*[=:]\s*['"][^'"]+['"]/gi, message: '发现可能的硬编码密码' }
        ];

        for (const { pattern, message } of securityIssues) {
            if (pattern.test(code)) {
                issues.push({
                    type: 'security',
                    severity: 'high',
                    message
                });
            }
        }

        return issues;
    }

    /**
     * 检查代码风格
     */
    checkStyle(code) {
        const lines = code.split('\n');
        const styleIssues = [];

        lines.forEach((line, index) => {
            // 行长度检查
            if (line.length > this.options.maxLineLength) {
                styleIssues.push({
                    line: index + 1,
                    type: 'line_length',
                    message: `行过长（${line.length} 字符）`
                });
            }

            // 检测尾随空格
            if (line.endsWith(' ') || line.endsWith('\t')) {
                styleIssues.push({
                    line: index + 1,
                    type: 'trailing_whitespace',
                    message: '存在尾随空格'
                });
            }
        });

        return styleIssues;
    }

    /**
     * 生成综合报告
     */
    generateReport(filePath) {
        console.log(`\n📋 代码质量检查报告: ${path.basename(filePath)}\n`);
        console.log('─'.repeat(50));

        const code = fs.readFileSync(filePath, 'utf-8');

        // 复杂度分析
        const complexity = this.analyzeComplexity(code);
        console.log(`\n🔢 圈复杂度: ${complexity.score} (${complexity.rating})`);
        if (complexity.warning) {
            console.log(`   ⚠️ 超过阈值 ${this.options.maxComplexity}，建议拆分函数`);
        }

        // 问题检测
        const issues = this.detectCommonIssues(code);
        if (issues.length > 0) {
            console.log(`\n🐛 发现 ${issues.length} 个问题:`);
            const bySeverity = {
                high: issues.filter(i => i.severity === 'high'),
                medium: issues.filter(i => i.severity === 'medium'),
                low: issues.filter(i => i.severity === 'low')
            };

            if (bySeverity.high.length > 0) {
                console.log('   🔴 高危:');
                bySeverity.high.forEach(i => console.log(`      - ${i.message}`));
            }
            if (bySeverity.medium.length > 0) {
                console.log('   🟡 中危:');
                bySeverity.medium.forEach(i => console.log(`      - ${i.message}`));
            }
            if (bySeverity.low.length > 0) {
                console.log('   🟢 低危:');
                bySeverity.low.forEach(i => console.log(`      - ${i.message}`));
            }
        } else {
            console.log('\n✅ 未发现常见问题');
        }

        // 风格检查
        const styleIssues = this.checkStyle(code);
        if (styleIssues.length > 0) {
            console.log(`\n🎨 风格问题: ${styleIssues.length} 处`);
        }

        // 综合评分
        const score = Math.max(0, 100 - 
            (complexity.warning ? 20 : 0) -
            (issues.filter(i => i.severity === 'high').length * 15) -
            (issues.filter(i => i.severity === 'medium').length * 5) -
            (styleIssues.length * 1)
        );

        console.log('\n' + '─'.repeat(50));
        console.log(`\n📊 综合评分: ${score}/100 ${score >= 80 ? '✅' : score >= 60 ? '🟡' : '❌'}`);

        return {
            score,
            complexity,
            issues,
            styleIssues
        };
    }
}

// CLI 使用示例
if (require.main === module) {
    const filePath = process.argv[2] || 'sample.js';
    const checker = new CodeQualityChecker({
        maxComplexity: 10,
        maxLineLength: 120
    });

    try {
        checker.generateReport(filePath);
    } catch (error) {
        console.error('检查失败:', error.message);
        process.exit(1);
    }
}

module.exports = CodeQualityChecker;


