!/usr/bin/env node
/**
 * Copilot 代码质量检查工具 - 演示代码
 * 功能：检查 AI 生成代码的常见问题
 */

class QualityChecker {
    constructor() {
        this.issues = [];
    }

    /**
     * 检测常见代码问题
     * @param {string} code - 待检查的代码
     * @returns {Array} 问题列表
     */
    check(code) {
        this.issues = [];

        // 检测 TODO（未完成的标志）
        if (/TODO|FIXME|HACK/.test(code)) {
            this.issues.push({
                type: 'incomplete',
                message: '发现未完成的 TODO/FIXME 标记',
                severity: 'medium'
            });
        }

        // 检测硬编码配置
        if (/timeout\s*[=:]\s*\d{4,}/.test(code)) {
            this.issues.push({
                type: 'hardcoded',
                message: '发现硬编码的超时值',
                severity: 'low'
            });
        }

        // 检测安全问题
        if (/eval\(|innerHTML\s*=/.test(code)) {
            this.issues.push({
                type: 'security',
                message: '可能存在安全风险',
                severity: 'high'
            });
        }

        return this.issues;
    }

    /**
     * 计算质量分数
     * @returns {number} 0-100 的质量分数
     */
    calculateScore() {
        let score = 100;
        for (const issue of this.issues) {
            if (issue.severity === 'high') score -= 20;
            if (issue.severity === 'medium') score -= 10;
            if (issue.severity === 'low') score -= 5;
        }
        return Math.max(0, score);
    }
}

// 使用示例
const checker = new QualityChecker();
const code = `
function fetchData() {
    // TODO: 添加错误处理
    const timeout = 999999;
    eval(userInput);
}
`;

const issues = checker.check(code);
const score = checker.calculateScore();

console.log('检查结果:');
console.log(`  发现 ${issues.length} 个问题`);
issues.forEach(i => console.log(`  - [${i.severity}] ${i.message}`));
console.log(`  质量分数: ${score}/100`);
